String name = “Fido”;
Dog myDog = new Dog(name, size);
x = size - 5;
if (x < 15) myDog.bark(8);
while (x > 3) {
 myDog.play();
}
int[] numList = {2,4,6,8};
System.out.print(“Hello”);
